-- PARTE 4/6 — conteúdo das iscas 13–18
update public.blog_templum_iscas set headline='Regularização no setor<br>alimentício, sem <em>surpresa</em><br>na próxima <em>fiscalização</em>.', subhead='Restaurantes, fábricas e distribuidores convivem com risco regulatório alto. Esse guia mostra o checklist de regularização e boas práticas que mantém a operação rodando.', benefits='["<strong>Mapa completo</strong> de exigências por tipo de operação.","<strong>ANVISA, MAPA, Vigilância Sanitária</strong>, quem fiscaliza o quê.","<strong>Boas práticas</strong> de fabricação e manipulação aplicadas.","Como reagir à <strong>autuação</strong> sem comprometer a operação."]'::jsonb, steps='[{"num":"01","title":"Classificação","text":"Como identificar exatamente o que sua operação é, e quem fiscaliza."},{"num":"02","title":"Alvarás e licenças","text":"Lista completa do que precisa ser emitido e renovado."},{"num":"03","title":"Boas Práticas (BPF)","text":"Procedimentos operacionais padrão e POPs essenciais."},{"num":"04","title":"Manipulação segura","text":"Higiene, temperatura, controle de pragas, o que fiscalização olha."},{"num":"05","title":"Rotulagem","text":"Regras de embalagem, ingredientes, alergênicos e nutricional."},{"num":"06","title":"Em caso de autuação","text":"Como responder, recorrer e ajustar, sem fechar as portas."}]'::jsonb, cta_title='Fiscalização <em>chega</em>.<br>A pergunta é se você<br>está <em>pronto</em>.', cta_copy='Empresas do setor alimentício que tratam regularização como check-list anual sofrem com autuações repetidas. O guia muda esse jogo.', cta_items='["Para restaurantes, indústrias e distribuidores","Inclui exemplos de POP","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-regularizacao-para-ramo-alimenticio';
update public.blog_templum_iscas set headline='Segurança de alimentos<br>que <em>protege</em> a marca<br>e o <em>consumidor</em>.', subhead='Recall e contaminação destroem reputação em dias. Esse guia mostra como estruturar segurança de alimentos seguindo as principais normas internacionais.', benefits='["Base de <strong>APPCC / HACCP</strong> aplicada ao seu processo.","Diferenças entre <strong>ISO 22000 e FSSC 22000</strong>.","<strong>Programa de pré-requisitos</strong> (PPRs) explicados.","Como evitar os <strong>erros típicos</strong> que geram recall."]'::jsonb, steps='[{"num":"01","title":"Análise de perigos","text":"Como aplicar APPCC ao seu processo específico."},{"num":"02","title":"PPRs","text":"Programa de pré-requisitos que sustenta o sistema."},{"num":"03","title":"Pontos críticos","text":"Identificação, monitoramento e correção em tempo real."},{"num":"04","title":"Rastreabilidade","text":"Como construir rastreabilidade da matéria-prima ao consumidor."},{"num":"05","title":"Resposta a incidente","text":"Plano de recall e comunicação que protege a marca."},{"num":"06","title":"Melhoria contínua","text":"Auditoria interna, análise crítica e cultura de segurança."}]'::jsonb, cta_title='Segurança de alimentos<br>é <em>seguro de marca</em>.', cta_copy='Um recall mal gerenciado já fechou empresas grandes. Esse guia mostra como blindar a operação antes que aconteça.', cta_items='["Para indústrias e food service","Base para certificação FSSC 22000","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-seguranca-de-alimentos';
update public.blog_templum_iscas set headline='FSSC 22000 na <em>prática</em>:<br>caso real de <em>implementação</em>.', subhead='Em vez de teoria, este material mostra como uma indústria de alimentos saiu do zero à certificação FSSC 22000, etapas, custos, prazos e resultados.', benefits='["<strong>Diagnóstico inicial</strong> e principais gaps encontrados.","<strong>Cronograma real</strong> de implementação por fases.","<strong>Custos diretos e indiretos</strong> envolvidos.","<strong>Resultados</strong> antes/depois, em números."]'::jsonb, steps='[{"num":"01","title":"Cenário inicial","text":"Onde a empresa estava quando começou o projeto."},{"num":"02","title":"Diagnóstico","text":"Principais gaps identificados em PPRs e APPCC."},{"num":"03","title":"Cronograma","text":"Como o projeto foi dividido em fases ao longo de 9 meses."},{"num":"04","title":"Investimento","text":"Custos com consultoria, infraestrutura, capacitação e auditoria."},{"num":"05","title":"Auditoria","text":"Como foi a auditoria de certificação e os ajustes finais."},{"num":"06","title":"Pós-certificação","text":"Resultados após 12 meses certificada, mercado, margem, clientes."}]'::jsonb, cta_title='Caso real é o melhor<br>parâmetro pra <em>decisão</em>.', cta_copy='Vê como a empresa do estudo decidiu, executou e colheu o resultado. Aprenda com escolhas que funcionaram, e com as que custaram caro.', cta_items='["Material baseado em projeto real","Foco em indústrias de alimentos","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-estudo-de-caso-fssc-22000';
update public.blog_templum_iscas set headline='OKR que <em>funciona</em>,<br>não OKR que vira<br>mais um <em>quadro</em>.', subhead='OKR mal implementado vira metas decoradas. Esse guia mostra como conduzir o ciclo de objetivos e resultados-chave gerando foco real no time.', benefits='["Diferença entre <strong>OKR e KPI</strong>, e quando usar cada um.","Como escrever <strong>objetivos inspiradores</strong> sem virar slogan.","<strong>Key Results</strong> mensuráveis, não atividades disfarçadas.","<strong>Ciclo trimestral</strong> com check-ins eficientes."]'::jsonb, steps='[{"num":"01","title":"Conceito","text":"O que OKR é, e o que não é. Onde Google, Intel e outras erraram no começo."},{"num":"02","title":"Como escrever","text":"Estrutura de objetivos e key results que cabem na realidade da sua empresa."},{"num":"03","title":"Cascateamento","text":"Como conectar OKRs da diretoria com OKRs de área e time."},{"num":"04","title":"Check-ins","text":"Ritmo semanal e quinzenal que mantém OKR vivo, sem virar reunião extra."},{"num":"05","title":"Avaliação","text":"Como pontuar key results no fim do trimestre, e o que fazer com 0.4."},{"num":"06","title":"Armadilhas","text":"Os erros típicos: OKR atividade, OKR muito fácil, KR sem dono."}]'::jsonb, cta_title='OKR é <em>foco</em>.<br>Sem foco, ninguém entrega.', cta_copy='Esse guia te leva do conceito ao primeiro ciclo prático em uma leitura. Sem teoria solta.', cta_items='["Aplicável a qualquer porte de empresa","Templates de objetivo e KR inclusos","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-okr';
update public.blog_templum_iscas set headline='Cliente contábil que <em>fica</em>,<br>e que <em>indica</em>.', subhead='Em escritório contábil, ganhar cliente é caro. Perder é barato, e silencioso. Esse guia mostra como estruturar relacionamento que reduz churn e gera indicação.', benefits='["Onde nasce o <strong>churn</strong> e como antecipar.","<strong>Cadência</strong> de contato que cabe na rotina do escritório.","Como pedir <strong>indicação</strong> sem soar invasivo.","<strong>NPS</strong> e métricas que importam no contábil."]'::jsonb, steps='[{"num":"01","title":"Diagnóstico","text":"Saúde do relacionamento, sinais de cliente em risco."},{"num":"02","title":"Cadência","text":"Como manter contato sem virar peso na rotina do contador."},{"num":"03","title":"Comunicação proativa","text":"Antecipar dúvida vale mais que responder rápido."},{"num":"04","title":"Pesquisa NPS","text":"Como aplicar NPS sem irritar, e o que fazer com a nota."},{"num":"05","title":"Pedido de indicação","text":"Quando, como e para quem pedir, sem desgastar o relacionamento."},{"num":"06","title":"Gestão de churn","text":"Quando o cliente sinaliza saída, o que fazer e o que não fazer."}]'::jsonb, cta_title='Cliente fiel é <em>margem</em>.<br>Indicação é <em>crescimento</em>.', cta_copy='Escritórios que estruturam relacionamento reduzem churn em 30-40%. Esse guia mostra o método.', cta_items='["Específico para o setor contábil","Templates de comunicação","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='e-book-gestao-de-relacionamentos';
update public.blog_templum_iscas set headline='Decisão de <em>empresário</em><br>sobre certificação e<br><em>gestão estruturada</em>.', subhead='Empresário que ouve "vamos implementar ISO" precisa de visão estratégica antes de mergulhar no operacional. Esse material foi feito pra essa decisão.', benefits='["Quando faz sentido <strong>certificar</strong>, e quando não.","<strong>Retorno financeiro</strong> esperado de cada norma.","Como evitar virar refém da <strong>consultoria</strong>.","<strong>Plano executivo</strong> que entrega resultado em 12 meses."]'::jsonb, steps='[{"num":"01","title":"Visão de longo prazo","text":"Onde sua empresa quer estar em 5 anos, e o que precisa para chegar."},{"num":"02","title":"Por que certificar","text":"Razões de mercado, financeiras e operacionais por trás de cada norma."},{"num":"03","title":"Investimento total","text":"Custos diretos e indiretos honestos, sem promessa vazia."},{"num":"04","title":"Retorno esperado","text":"Métricas que mostram retorno da certificação em 12-24 meses."},{"num":"05","title":"Sobre consultoria","text":"Como contratar bem, e como evitar dependência."},{"num":"06","title":"Plano de 12 meses","text":"Roteiro executivo do que esperar mês a mês."}]'::jsonb, cta_title='Decisão de empresário<br>precisa de <em>visão clara</em>.', cta_copy='Esse material te dá visão estratégica antes da decisão. Sem técnico demais, sem genérico demais.', cta_items='["Linguagem executiva","Aplicável a qualquer setor","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='ebook-empresarios';
